#include <cuda.h>
#include <stdlib.h>
#include <stdio.h>

#include "../common.h"

#include "../util/timer/timer.h"

#include "../util/cuda_helper.h"

__global__ void kernel_cuda(
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans,
    int threadsPerBlock)
{
    int bid = blockIdx.x;
    if (bid >= count) return;

    int thid;
    long current_node = currKnode[bid];
    long offset_val = offset[bid];
    int key_val = keys[bid];

    for (int i = 0; i < maxheight; i++) {
        for (thid = 0; thid < threadsPerBlock; thid++) {
            if (thid < order) {
                if ((knodes[current_node].keys[thid] <= key_val) && (knodes[current_node].keys[thid+1] > key_val)) {
                    if (knodes[offset_val].indices[thid] < knodes_elem) {
                        offset_val = knodes[offset_val].indices[thid];
                    }
                }
            }
        }
        current_node = offset_val;
    }

    for (thid = 0; thid < threadsPerBlock; thid++) {
        if (thid < order) {
            if (knodes[current_node].keys[thid] == key_val) {
                ans[bid].value = records[knodes[current_node].indices[thid]].value;
            }
        }
    }
}

