    cudaMalloc(&d_offset, count * sizeof(long));
    cudaMemcpy(d_offset, offset, count * sizeof(long), cudaMemcpyHostToDevice);

    cudaMalloc(&d_lastKnode, count * sizeof(long));
    cudaMemcpy(d_lastKnode, lastKnode, count * sizeof(long), cudaMemcpyHostToDevice);

    cudaMalloc(&d_offset_2, count * sizeof(long));
    cudaMemcpy(d_offset_2, offset_2, count * sizeof(long), cudaMemcpyHostToDevice);

