    );

    checkCUDAError("kernel_cuda_2 launch");

    cudaMemcpy(recstart, d_recstart, count * sizeof(int), cudaMemcpyDeviceToHost);
    cudaMemcpy(reclength, d_reclength, count * sizeof(int), cudaMemcpyDeviceToHost);

    cudaFree(d_knodes);
